package com.chaobo.scm.supplier.application.qualification;
import com.chaobo.scm.common.api.PageResult;import com.chaobo.scm.common.error.*;import com.chaobo.scm.supplier.application.shared.*;import com.chaobo.scm.supplier.domain.qualification.*;import com.chaobo.scm.supplier.domain.shared.*;import org.springframework.stereotype.Service;import org.springframework.transaction.annotation.Transactional;import java.time.*;import java.util.function.*;
@Service public class SupplierQualificationApplicationService {private final SupplierQualificationRepository repo;private final SupplierQualificationReadModelPort read;private final OutboxRepository outbox;private final AuditLogRepository audit;private final IdentifierGenerator ids;private final TransactionalCommandExecutor executor;public SupplierQualificationApplicationService(SupplierQualificationRepository repo,SupplierQualificationReadModelPort read,OutboxRepository outbox,AuditLogRepository audit,IdentifierGenerator ids,TransactionalCommandExecutor executor){this.repo=repo;this.read=read;this.outbox=outbox;this.audit=audit;this.ids=ids;this.executor=executor;}@Transactional(readOnly=true)public PageResult<SupplierQualificationView> page(Long supplierId,Long scope,Integer status,int page,int size){if(page<1||size<1||size>100)throw new BusinessException(ErrorCode.VALIDATION_FAILED,"分页参数不合法");return read.page(scope==null?supplierId:scope,status,page,size);}@Transactional(readOnly=true)public SupplierQualificationView detail(long id,Long scope){var v=read.detail(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"供应商资质不存在"));if(scope!=null&&scope!=v.supplierId())throw new BusinessException(ErrorCode.NOT_FOUND,"供应商资质不存在");return v;}@Transactional public CommandResult submit(long supplierId,String type,String number,LocalDate from,LocalDate to,String attachment,CommandContext context){context.requirePermission("supplier:qualification:submit");context.requireSupplierScope(supplierId);return executor.execute("supplier:qualification",context,type+number+to,()->persist(SupplierQualificationAggregate.submit(supplierId,type,number,from,to,attachment,context.operatorId(),ids),context,"SUBMIT_QUALIFICATION",null));}@Transactional public CommandResult approve(long id,int version,String remark,CommandContext context){context.requirePermission("supplier:qualification:approve");return change(id,version,"APPROVE_QUALIFICATION",context,a->a.approve(remark,context.operatorId(),ids));}@Transactional public CommandResult reject(long id,int version,String reason,CommandContext context){context.requirePermission("supplier:qualification:approve");return change(id,version,"REJECT_QUALIFICATION",context,a->a.reject(reason,context.operatorId(),ids));}@Transactional public void expire(long id){var a=repo.findById(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"供应商资质不存在"));String before=snapshot(a);a.expire(0,ids);if(a.status()==QualificationStatus.EXPIRED)persist(a,new CommandContext(0,"系统",0,null,"qualification-expire-"+id,null,"qualification-expire-"+id,java.util.Set.of()),"EXPIRE_QUALIFICATION",before);}private CommandResult change(long id,int version,String op,CommandContext c,Consumer<SupplierQualificationAggregate> action){return executor.execute("supplier:qualification",c,id+":"+version+op,()->{var a=repo.findById(id).orElseThrow(()->new BusinessException(ErrorCode.NOT_FOUND,"供应商资质不存在"));c.requireSupplierScope(a.supplierId());if(a.version()!=version)throw new BusinessException(ErrorCode.VERSION_CONFLICT,"资质已被更新");String before=snapshot(a);action.accept(a);return persist(a,c,op,before);});}private CommandResult persist(SupplierQualificationAggregate a,CommandContext c,String op,String before){repo.save(a,c.operatorId());var events=a.pullEvents();outbox.saveAll(events);audit.save(c,op,"SUPPLIER_QUALIFICATION",a.id(),Long.toString(a.id()),before,snapshot(a));return new CommandResult(a.id(),Long.toString(a.id()),a.status().code(),a.status().label(),a.version(),events.isEmpty()?null:events.getLast().eventCode(),false);}private String snapshot(SupplierQualificationAggregate a){return "{\"qualificationId\":%d,\"status\":%d,\"validTo\":\"%s\",\"version\":%d}".formatted(a.id(),a.status().code(),a.to(),a.version());}}
